  constructor(private frameService: FsUiFrameService) {
    this.frameService.isMenuClosed.subscribe((bool: boolean) => {
      if (bool) {
        this.openedClass = ""
      } else {
        this.openedClass = "opened"
      }
    })
  }

  ngOnInit() {
  }

  ngOnDestroy() {
    this.frameService.isMenuClosed.unsubscribe()
  }

}

